func TestParseFlexibleTime(t *testing.T) {
	tests := []struct {
		name  string
		input string
		ok    bool
	}{
		{"rfc3339", "2026-05-30T09:00:00Z", true},
		{"naive datetime", "2026-05-30T09:00:00", true},
		{"bare date", "2026-05-30", true},
		{"empty", "", false},
		{"garbage", "not-a-date", false},
		{"epoch number string", "1748600000", false},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, ok := parseFlexibleTime(tt.input)
			if ok != tt.ok {
				t.Fatalf("parseFlexibleTime(%q) ok = %v, want %v", tt.input, ok, tt.ok)
			}
		})
	}
}

func TestDeviceOffline(t *testing.T) {
	now := time.Date(2026, 6, 6, 12, 0, 0, 0, time.UTC)
	tests := []struct {
		name     string
		lastSeen string
		days     int
		want     bool
	}{
		{"seen this morning", "2026-06-06T08:00:00Z", 1, false},
		{"seen last week", "2026-05-30T08:00:00Z", 1, true},
		{"unparseable surfaces as offline", "garbage", 1, true},
		{"empty surfaces as offline", "", 1, true},
		{"exactly at boundary not offline", "2026-06-05T12:00:00Z", 1, false},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := deviceOffline(tt.lastSeen, now, tt.days); got != tt.want {
				t.Fatalf("deviceOffline(%q, now, %d) = %v, want %v", tt.lastSeen, tt.days, got, tt.want)
			}
		})
	}
}

