func TestClientRiskRanksAcmeFirst(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelClientRiskCmd, "--db", dbPath)

	var rows []clientRiskRow
	mustUnmarshal(t, out, &rows)
	if len(rows) != 2 {
		t.Fatalf("client rows = %d, want 2", len(rows))
	}
	// Acme: 3 alerts (x2) + 1 screenshot fail (x3) = 9.
	// Globex: 2 screenshot fails (glob-fs1 passes; archived glob-old still
	// counts in the per-client screenshot tally) — ranked below Acme.
	if rows[0].Client != "Acme Corp" {
		t.Fatalf("top risk client = %q, want Acme Corp (rows: %+v)", rows[0].Client, rows)
	}
	if rows[0].RiskScore <= rows[1].RiskScore {
		t.Fatalf("risk ordering broken: %+v", rows)
	}
}
